#include <iostream>

int square(int x);
int cube(int x);

int main()
{
    int n;
    std::cin >> n;
    std::cout << "Square: " << square(n) << "\n";
    std::cout << "Cube: " << cube(n) << "\n";
    return 0;
}

int square(int x)
{
    return x * x;
}

int cube(int x)
{
    return x * x * x;
}

